169	// validateCompileConfig validates the configuration flags before compilation
170	// This is extracted for faster testing without full compilation
171	func validateCompileConfig(config CompileConfig) error {
172		compileValidationLog.Printf("Validating compile config: files=%d, dependabot=%v, purge=%v, workflowDir=%s", len(config.MarkdownFiles), config.Dependabot, config.Purge, config.WorkflowDir)
173	
174		// Validate dependabot flag usage
175		if config.Dependabot {
176			if len(config.MarkdownFiles) > 0 {
177				compileValidationLog.Print("Config validation failed: dependabot flag with specific files")
178				return errors.New("--dependabot flag cannot be used with specific workflow files")
179			}
180			if config.WorkflowDir != "" && config.WorkflowDir != ".github/workflows" {
181				compileValidationLog.Printf("Config validation failed: dependabot with custom dir: %s", config.WorkflowDir)
182				return errors.New("--dependabot flag cannot be used with custom --dir")
183			}
184		}
185	
186		// Validate purge flag usage
187		if config.Purge && len(config.MarkdownFiles) > 0 {
188			compileValidationLog.Print("Config validation failed: purge flag with specific files")
189			return errors.New("--purge flag can only be used when compiling all markdown files (no specific files specified)")
190		}
191	
192		// Validate workflow directory path
193		if config.WorkflowDir != "" && filepath.IsAbs(config.WorkflowDir) {
194			compileValidationLog.Printf("Config validation failed: absolute path in workflowDir: %s", config.WorkflowDir)
195			return fmt.Errorf("--dir must be a relative path, got: %s", config.WorkflowDir)
196		}
197	
198		compileValidationLog.Print("Config validation successful")
199		return nil
200	}
201	
202	// validateActionModeConfig validates the action mode configuration
203	func validateActionModeConfig(actionMode string) error {
204		if actionMode == "" {
205			return nil
206		}
207	
208		mode := workflow.ActionMode(actionMode)
209		if !mode.IsValid() {
210			return fmt.Errorf("invalid action mode '%s'. Must be 'dev', 'release', 'script', or 'action'", actionMode)
211		}
212	
213		return nil
214	}
215	
216	// sanitizeValidationResults creates a sanitized copy of validation results with all
217	// error and warning messages sanitized to remove potential secret key names.
218	// This is applied at the JSON output boundary to ensure no sensitive information
219	// is leaked regardless of where error messages originated.
220	func sanitizeValidationResults(results []ValidationResult) []ValidationResult {
221		if results == nil {
222			return nil
223		}
224	
225		compileValidationLog.Printf("Sanitizing validation results: workflow_count=%d", len(results))
226	
227		sanitizeError := func(e CompileValidationError) CompileValidationError {
228			return CompileValidationError{
229				Type:    e.Type,
230				Message: stringutil.SanitizeErrorMessage(e.Message),
231				Line:    e.Line,
232			}
233		}
234	
235		return sliceutil.Map(results, func(result ValidationResult) ValidationResult {
236			return ValidationResult{
237				Workflow:     result.Workflow,
238				Valid:        result.Valid,
239				CompiledFile: result.CompiledFile,
240				Errors:       sliceutil.Map(result.Errors, sanitizeError),
241				Warnings:     sliceutil.Map(result.Warnings, sanitizeError),
242				Labels:       result.Labels,
243			}
244		})
245	}
